class Solution {
public:
    vector<int> twoSum(vector<int>& nums, int target) {
        unordered_map<int, int> hashtable;
        for (int i = 0; i < nums.size(); ++i) {
            auto it = hashtable.find(target - nums[i]); // 先查：我需要的另一半是否已出现
            if (it != hashtable.end()) {
                return {it->second, i};
            }
            hashtable[nums[i]] = i; // 后存：保证不会用到自己
        }
        return {};
    }
};
